create table if not exists public.blog_posts (id uuid primary key default gen_random_uuid(),title text not null,body text not null,published boolean not null default true,author_id uuid references public.profiles(id) on delete set null,created_at timestamptz not null default now());create table if not exists public.notifications (id uuid primary key default gen_random_uuid(),title text not null,body text not null,kind text not null default 'info',created_by uuid references public.profiles(id) on delete set null,created_at timestamptz not null default now());alter table public.blog_posts enable row level security;alter table public.notifications enable row level security;drop policy if exists "published blogs readable" on public.blog_posts;create policy "published blogs readable" on public.blog_posts for select using (published=true);drop policy if exists "notifications readable" on public.notifications;create policy "notifications readable" on public.notifications for select to authenticated using (true);